diff --git a/include/nlohmann/ordered_map.hpp b/include/nlohmann/ordered_map.hpp
index d8606f8..b45ab97 100644
--- a/include/nlohmann/ordered_map.hpp
+++ b/include/nlohmann/ordered_map.hpp
@@ -166,10 +166,11 @@ template <class Key, class T, class IgnoredLess = std::less<Key>,
             if (m_compare(it->first, key))
             {
                 // Since we cannot move const Keys, re-construct them in place
+                auto alloc = Container::get_allocator();
                 for (auto next = it; ++next != this->end(); ++it)
                 {
-                    it->~value_type(); // Destroy but keep allocation
-                    new (&*it) value_type{std::move(*next)};
+                    std::allocator_traits<Allocator>::destroy(alloc, std::addressof(*it));
+                    std::allocator_traits<Allocator>::construct(alloc, std::addressof(*it), std::move(*next));
                 }
                 Container::pop_back();
                 return 1;
@@ -187,10 +188,11 @@ template <class Key, class T, class IgnoredLess = std::less<Key>,
             if (m_compare(it->first, key))
             {
                 // Since we cannot move const Keys, re-construct them in place
