                 for (auto next = it; ++next != this->end(); ++it)
                 {
-                    it->~value_type(); // Destroy but keep allocation
-                    new (&*it) value_type{std::move(*next)};
+                    std::allocator_traits<Allocator>::destroy(alloc, std::addressof(*it));
+                    std::allocator_traits<Allocator>::construct(alloc, std::addressof(*it), std::move(*next));
                 }
                 Container::pop_back();
                 return 1;
@@ -236,8 +238,9 @@ template <class Key, class T, class IgnoredLess = std::less<Key>,

         for (auto it = first; std::next(it, elements_affected) != Container::end(); ++it)
         {
-            it->~value_type(); // destroy but keep allocation
-            new (&*it) value_type{std::move(*std::next(it, elements_affected))}; // "move" next element to it
+            auto alloc = Container::get_allocator();
+            std::allocator_traits<Allocator>::destroy(alloc, std::addressof(*it)); // destroy but keep allocation
+            std::allocator_traits<Allocator>::construct(alloc, std::addressof(*it), std::move(*std::next(it, elements_affected))); // "move" next element to it
         }
